function nextInvNum(){var y=String(new Date().getFullYear());var prefix=y;var s=(invoices||[]).filter(function(i){if(i.status==='draft')return false;var n=String(i.number||'');if(n.indexOf(prefix)!==0)return false;return /^\d+$/.test(n.slice(prefix.length))});var mx=s.reduce(function(m,i){var rest=String(i.number||'').slice(prefix.length);var n=parseInt(rest,10);return Math.max(m,isNaN(n)?0:n)},0);return prefix+String(mx+1).padStart(4,'0')}
function nextReInvNum(){var d=new Date();var yy=String(d.getFullYear()).slice(-2);var mm=String(d.getMonth()+1).padStart(2,'0');var dd=String(d.getDate()).padStart(2,'0');var datePart='RE-'+yy+mm+dd+'-';var s=(invoices||[]).filter(function(i){return i.status!=='draft'&&String(i.number||'').indexOf(datePart)===0});var mx=s.reduce(function(m,i){var parts=String(i.number||'').split('-');var n=parseInt(parts[2]||'0',10);return Math.max(m,isNaN(n)?0:n)},0);return datePart+(mx+1)}
function onIeNumFormatChange(){var sel=document.querySelector('input[name="ieNumFormat"]:checked');var numEl=document.getElementById('ieNumber');if(!sel||!numEl)return;numEl.value=(sel.value==='re')?nextReInvNum():nextInvNum()}
function createInvoiceFromOrder(oid){
var o=orders.find(function(x){return x.id===oid});
if(!o){alert('Auftrag nicht gefunden.');return}
var vr=companyData.kleinunternehmer?0:(companyData.defaultVat||0.19);
var services=ensureArray(o.services);
var workLines=[];
var prepayLines=[];
services.forEach(function(s,i){
if(!s)return;
if(s.costType==='prepayment'){
var netAmount=Number(s.prepaymentNet!=null?s.prepaymentNet:s.prepaymentGross)||0;
if(!(netAmount>0))return;
var netDed=netAmount;
var descParts=[];
if(s.prepaymentDate)descParts.push(String(s.prepaymentDate));
if(s.description)descParts.push(String(s.description));
prepayLines.push({id:'pp_'+Date.now()+'_'+i,pos:0,title:String(s.title||'Vorauszahlung'),description:descParts.join(' · '),qty:1,unit:'Pauschal',unitPrice:-netDed,lineTotal:-netDed});
return
}
if(s.costType==='position'){
var q=Number(s.quantity||0),up=Number(s.unitPrice||0);
workLines.push({id:'ln_'+Date.now()+'_'+i,pos:0,title:s.title||'',description:s.description||'',qty:q,unit:s.unit||'Pauschal',unitPrice:up,lineTotal:q*up,costType:'position'});
return
}
var q2=Number(s.quantity);if(!(q2>0))q2=1;
var u2=s.unit||'Pauschal';
var up2=Number(s.unitPrice);
var mc=Number(s.materialCost||0);
if((!isFinite(up2)||up2<=0)&&mc>0)up2=mc/q2;
var total=(isFinite(mc)&&mc>0)?mc:(q2*up2);
up2=q2>0?total/q2:0;
workLines.push({id:'ln_'+Date.now()+'_'+i,pos:0,title:s.title||'',description:s.description||'',qty:q2,unit:u2,unitPrice:up2,lineTotal:total,costType:'material'})
});
var legacyPps=ensureArray(o.prepayments).filter(function(p){return p&&isFinite(Number(p.amount))&&Number(p.amount)>0});
legacyPps.forEach(function(p,idx){
var netAmount=Number(p.amount)||0;
var netDed=netAmount;
var descParts=[];
if(p.date)descParts.push(String(p.date));
if(p.note)descParts.push(String(p.note));
prepayLines.push({id:'pp_'+Date.now()+'_'+idx,pos:0,title:'Vorauszahlung',description:descParts.join(' · '),qty:1,unit:'Pauschal',unitPrice:-netDed,lineTotal:-netDed})
});
if(!workLines.length){alert('Bitte zuerst Leistungen hinzufügen.');return}
var lines=workLines.concat(prepayLines);
lines.forEach(function(l,i){l.pos=i+1;l.lineTotal=(Number(l.qty)||0)*(Number(l.unitPrice)||0)});
var net=lines.reduce(function(s,l){return s+(Number(l.lineTotal)||0)},0);
var id_=new Date(),dd=new Date();
dd.setDate(dd.getDate()+(companyData.zahlungsziel||14));
var cu=customers.find(function(c){return c.id===o.customerId})||{};
var inv={id:'inv_'+Date.now(),number:'',orderId:o.id,customerId:o.customerId||'',customerName:o.customer||'',customerAddress:[cu.street,[cu.zip,cu.city].filter(Boolean).join(' ')].filter(Boolean).join(', '),customerSalutation:cu.salutation||'',customerFirstName:cu.firstName||'',customerLastName:cu.lastName||'',customerCompany:cu.company||'',customerEmail:cu.email||'',object:o.object||'',currency:'EUR',issueDate:id_.toISOString().slice(0,10),dueDate:dd.toISOString().slice(0,10),lines:lines,netTotal:net,vatRate:vr,vatTotal:net*vr,grossTotal:net*(1+vr),status:'draft',kleinunternehmer:!!companyData.kleinunternehmer,companySnapshot:JSON.parse(JSON.stringify(companyData)),createdAt:Date.now()};
invoices.unshift(inv);
saveData();
showSection('invoices');
renderInvoices();
showInvoiceEditModal(inv.id)
}
function _lineVatRate(inv,l){if(inv&&inv.kleinunternehmer)return 0;var r=l&&l.vatRate;if(r==null||r===''||isNaN(Number(r)))return Number(inv&&inv.vatRate)||0;return Number(r)}
function _lineTaxCategory(inv,l){if(inv&&inv.kleinunternehmer)return'E';if(l&&l.taxCategory)return l.taxCategory;var r=_lineVatRate(inv,l);return r>0?'S':'Z'}
function recalcInvoice(inv){var lines=ensureArray(inv.lines);var net=0,vat=0;var byRate={};lines.forEach(function(l){var lt=Number(l.lineTotal)||0;var r=_lineVatRate(inv,l);var lv=lt*r;net+=lt;vat+=lv;var key=r.toFixed(4);if(!byRate[key])byRate[key]={rate:r,taxCategory:_lineTaxCategory(inv,l),net:0,vat:0};byRate[key].net+=lt;byRate[key].vat+=lv});inv.netTotal=net;inv.vatTotal=vat;inv.grossTotal=net+vat;inv.vatBreakdown=Object.keys(byRate).map(function(k){return byRate[k]});return inv}
function applyIeDueDateModeUi(){var dueMode=document.getElementById('ieDueDateMode');var dateEl=document.getElementById('ieDueDate');if(!dueMode||!dateEl)return;var mode=dueMode.value==='sofort'?'sofort':'date';if(mode==='sofort'){dateEl.style.display='none';dueMode.style.flex='1';dueMode.style.maxWidth='none'}else{dateEl.style.display='';dueMode.style.flex='0 0 130px';dueMode.style.minWidth='130px';dueMode.style.maxWidth='130px'}}
