function _getIeField(id){var el=document.getElementById(id);return el?String(el.value||'').trim():''}
function showInvoiceEditModal(id){var inv=invoices.find(function(i){return i.id===id});if(!inv)return;document.getElementById('ieId').value=inv.id;var titleEl=document.getElementById('invoiceEditModalTitle');if(titleEl)titleEl.textContent=inv.status==='draft'?'Rechnungsentwurf bearbeiten':'Rechnung bearbeiten';var saveBtn=document.getElementById('ieSaveBtn');if(saveBtn)saveBtn.textContent=inv.status==='draft'?'Entwurf speichern':'Rechnung speichern';var finalizeBtn=document.getElementById('ieFinalizeBtn');if(finalizeBtn)finalizeBtn.style.display=inv.status==='draft'?'':'none';var numEl=document.getElementById('ieNumber');if(numEl)numEl.value=String(inv.number||'').trim()||(inv.status==='draft'?nextInvNum():'');var fmtRow=document.getElementById('ieNumFormatRow');if(fmtRow){if(inv.status==='draft'){fmtRow.style.display='';var curNum=String(numEl?numEl.value:'').trim();var isRe=curNum.indexOf('RE-')===0;var stdRadio=document.querySelector('input[name="ieNumFormat"][value="standard"]');var reRadio=document.querySelector('input[name="ieNumFormat"][value="re"]');if(stdRadio)stdRadio.checked=!isRe;if(reRadio)reRadio.checked=isRe}else{fmtRow.style.display='none'}}document.getElementById('ieObject').value=inv.object||'';document.getElementById('ieIssueDate').value=inv.issueDate;var dueMode=document.getElementById('ieDueDateMode');var dueDateEl=document.getElementById('ieDueDate');if(dueMode)dueMode.value=(inv.dueDate==='sofort')?'sofort':'date';if(dueDateEl)dueDateEl.value=(inv.dueDate&&inv.dueDate!=='sofort')?inv.dueDate:'';applyIeDueDateModeUi();_setIeField('ieServiceDateFrom',inv.serviceDateFrom||inv.leistungsdatum||'');_setIeField('ieServiceDateTo',inv.serviceDateTo||'');_setIeField('ieBestellnummer',inv.bestellnummerKunde||'');var brefDefault=inv.buyerReference||'';if(!brefDefault&&inv.customerId){var _cust=customers.find(function(x){return x.id===inv.customerId});if(_cust)brefDefault=_cust.buyerReference||_cust.kundennummer||''}_setIeField('ieBuyerReference',brefDefault);document.getElementById('ieKleinunternehmer').checked=!!inv.kleinunternehmer;var vs=document.getElementById('ieVatRate');vs.value=String(inv.vatRate);vs.disabled=!!inv.kleinunternehmer;document.getElementById('ieKUHint').style.display=inv.kleinunternehmer?'block':'none';var baSelect=document.getElementById('ieBankAccountId');if(baSelect){baSelect.innerHTML='<option value="">-- Keine --</option>'+(companyData.bankAccounts||[]).map(function(ba){return'<option value="'+escAttr(ba.id)+'"'+(inv.bankAccountId===ba.id?' selected':'')+'>'+escAttr(ba.label||'Konto')+' ('+escAttr(ba.iban||'')+')</option>'}).join('')}renderInvoiceEditLines(inv);document.getElementById('invoiceEditModal').classList.add('active')}
function hideInvoiceEditModal(){document.getElementById('invoiceEditModal').classList.remove('active')}
function toggleIeDueDateMode(){var dueMode=document.getElementById('ieDueDateMode');var mode=dueMode&&dueMode.value==='sofort'?'sofort':'date';var dateEl=document.getElementById('ieDueDate');applyIeDueDateModeUi();var invId=document.getElementById('ieId').value;var inv=invoices.find(function(i){return i.id===invId});if(!inv)return;if(mode==='sofort'){inv.dueDate='sofort';saveDataSoon();return}if(dateEl){var v=String(dateEl.value||'').trim();if(!/^\d{4}-\d{2}-\d{2}$/.test(v)){var base=new Date(String(inv.issueDate||new Date().toISOString().slice(0,10))+'T00:00:00');if(!isFinite(base.getTime()))base=new Date();base.setDate(base.getDate()+(companyData.zahlungsziel||14));v=base.toISOString().slice(0,10);dateEl.value=v}inv.dueDate=v;saveDataSoon()}}
