function renderInvoiceEditLines(inv){var c=document.getElementById('ieLinesList');if(!c)return;if(!inv.lines||!inv.lines.length){c.innerHTML='<p class="text-gray-400 text-center py-4">Keine Positionen</p>';updateIeTotals(inv);return}c.innerHTML=inv.lines.map(function(l,i){return'<div class="border border-gray-200 rounded-lg p-3 mb-2 ie-drag-item" id="ieline_'+l.id+'" draggable="true" ondragstart="ieLineDragStart(event,'+i+',\''+inv.id+'\')" ondragover="ieLineDragOver(event)" ondrop="ieLineDrop(event,\''+inv.id+'\','+i+')" ondragend="ieLineDragEnd()"><div class="flex justify-between items-start gap-3"><div class="flex-1"><div class="grid grid-cols-12 gap-2"><div class="col-span-1 text-center font-bold text-gray-400 pt-1" style="cursor:grab;user-select:none" title="Ziehen zum Verschieben"><span style="display:block;font-size:16px;color:#d1d5db;line-height:1.2">&#x283F;</span>'+(i+1)+'</div><div class="col-span-5 flex gap-1 items-center"><input type="text" value="'+escAttr(l.title)+'" onchange="updateIeLine(\''+inv.id+'\',\''+l.id+'\',\'title\',this.value)" class="input flex-1" style="padding:.5rem .75rem;font-size:.85rem" placeholder="Bezeichnung"><button type="button" onclick="aiImproveLineText(\''+inv.id+'\',\''+l.id+'\')" class="btn btn-secondary btn-sm ai-improve-btn" style="padding:.35rem .5rem;font-size:.75rem;white-space:nowrap;flex-shrink:0" title="Text mit KI verbessern">&#129302; KI</button></div><div class="col-span-2"><input type="number" value="'+l.qty+'" step="0.01" min="0" onchange="updateIeLine(\''+inv.id+'\',\''+l.id+'\',\'qty\',this.value)" class="input" style="padding:.5rem .75rem;font-size:.85rem" placeholder="Menge"></div><div class="col-span-2"><input type="number" value="'+l.unitPrice+'" step="0.01" min="-999999" onchange="updateIeLine(\''+inv.id+'\',\''+l.id+'\',\'unitPrice\',this.value)" class="input" style="padding:.5rem .75rem;font-size:.85rem" placeholder="EP"></div><div class="col-span-2 text-right pt-2 font-bold text-green-600">'+fmtCur(l.lineTotal)+'</div></div><div class="grid grid-cols-12 gap-2 mt-1"><div class="col-span-1"></div><div class="col-span-5"><textarea rows="2" onchange="updateIeLine(\''+inv.id+'\',\''+l.id+'\',\'description\',this.value)" class="input" style="padding:.55rem .75rem;font-size:.85rem;color:#334155;line-height:1.25;min-height:54px;resize:vertical;background:#f8fafc" placeholder="Beschreibung / Zusatztext (optional)">'+esc(l.description||'')+'</textarea></div><div class="col-span-2"><select onchange="updateIeLine(\''+inv.id+'\',\''+l.id+'\',\'unit\',this.value)" class="input" style="padding:.4rem .5rem;font-size:.8rem"><option'+(l.unit==='Pauschal'?' selected':'')+'>Pauschal</option><option'+(l.unit==='Stk'?' selected':'')+'>Stk</option><option'+(l.unit==='m\u00b2'?' selected':'')+'>m\u00b2</option><option'+(l.unit==='m'?' selected':'')+'>m</option><option'+(l.unit==='kg'?' selected':'')+'>kg</option><option'+(l.unit==='Std'?' selected':'')+'>Std</option></select></div><div class="col-span-4 text-right"><button onclick="removeIeLine(\''+inv.id+'\',\''+l.id+'\')" class="btn btn-secondary btn-sm btn-danger" style="padding:.25rem .75rem;font-size:.75rem">Entfernen</button></div></div></div></div></div>'}).join('');updateIeTotals(inv)}
function updateIeLine(invId,lineId,field,val){var inv=invoices.find(function(i){return i.id===invId});if(!inv)return;var l=inv.lines.find(function(x){return x.id===lineId});if(!l)return;if(field==='qty'||field==='unitPrice'){l[field]=parseFloat(val)||0;l.lineTotal=l.qty*l.unitPrice}else{l[field]=val}recalcInvoice(inv);renderInvoiceEditLines(inv);saveDataSoon()}
