function saveInvoiceEdit(e){if(e)e.preventDefault();var id=document.getElementById('ieId').value;var inv=invoices.find(function(i){return i.id===id});if(!inv)return;var numEl=document.getElementById('ieNumber');var newNum=numEl?String(numEl.value||'').trim():'';if(inv.status!=='draft'&&!newNum){alert('Bitte eine Rechnungsnummer eingeben.');return}if(newNum){var dup=invoices.find(function(i){return i.status!=='draft'&&String(i.number||'').trim()===newNum&&i.id!==id});if(dup){alert('Diese Rechnungsnummer existiert bereits!');return}}inv.number=newNum;inv.object=document.getElementById('ieObject').value;inv.issueDate=document.getElementById('ieIssueDate').value;var dueModeEl=document.getElementById('ieDueDateMode');inv.dueDate=(dueModeEl&&dueModeEl.value==='sofort')?'sofort':document.getElementById('ieDueDate').value;inv.serviceDateFrom=_getIeField('ieServiceDateFrom');inv.serviceDateTo=_getIeField('ieServiceDateTo');inv.bestellnummerKunde=_getIeField('ieBestellnummer');inv.buyerReference=_getIeField('ieBuyerReference');inv.kleinunternehmer=document.getElementById('ieKleinunternehmer').checked;inv.vatRate=inv.kleinunternehmer?0:parseFloat(document.getElementById('ieVatRate').value)||0.19;var baSelect=document.getElementById('ieBankAccountId');if(baSelect){inv.bankAccountId=baSelect.value;var baSel=(companyData.bankAccounts||[]).find(function(b){return b.id===baSelect.value});inv.bankAccount=baSel?{label:baSel.label,bank:baSel.bank,owner:baSel.owner,iban:baSel.iban,bic:baSel.bic}:null}recalcInvoice(inv);saveData();hideInvoiceEditModal();renderInvoices();if(selectedInvoiceId===id)renderInvoiceDetailModal(id)}
function finalizeInvoice(id){
var inv=invoices.find(function(i){return i.id===id});
if(!inv)return;
if(inv.status!=='draft'){alert('Nur Entw\u00fcrfe k\u00f6nnen finalisiert werden.');return}
if(!inv.lines||!inv.lines.length){alert('Bitte mindestens eine Position hinzuf\u00fcgen.');return}
var ieId=document.getElementById('ieId');
var desiredNum='';
if(ieId&&ieId.value===id){
var numEl=document.getElementById('ieNumber');desiredNum=numEl?String(numEl.value||'').trim():'';
var objEl=document.getElementById('ieObject');if(objEl)inv.object=objEl.value;
var issueEl=document.getElementById('ieIssueDate');if(issueEl)inv.issueDate=issueEl.value;
var dueModeEl=document.getElementById('ieDueDateMode');
var dueEl=document.getElementById('ieDueDate');
inv.dueDate=(dueModeEl&&dueModeEl.value==='sofort')?'sofort':(dueEl?dueEl.value:inv.dueDate);
inv.serviceDateFrom=_getIeField('ieServiceDateFrom');
inv.serviceDateTo=_getIeField('ieServiceDateTo');
inv.bestellnummerKunde=_getIeField('ieBestellnummer');
inv.buyerReference=_getIeField('ieBuyerReference');
inv.kleinunternehmer=document.getElementById('ieKleinunternehmer').checked;
inv.vatRate=inv.kleinunternehmer?0:parseFloat(document.getElementById('ieVatRate').value)||0.19;
var baSelect=document.getElementById('ieBankAccountId');
if(baSelect){
inv.bankAccountId=baSelect.value;
var baSel=(companyData.bankAccounts||[]).find(function(b){return b.id===baSelect.value});
inv.bankAccount=baSel?{label:baSel.label,bank:baSel.bank,owner:baSel.owner,iban:baSel.iban,bic:baSel.bic}:null
}
}
if(!/^\d{4}-\d{2}-\d{2}$/.test(String(inv.issueDate||'')))inv.issueDate=new Date().toISOString().slice(0,10);
if(inv.dueDate!=='sofort'){
var dv=String(inv.dueDate||'');
if(!/^\d{4}-\d{2}-\d{2}$/.test(dv))inv.dueDate=addDaysIso(inv.issueDate,companyData.zahlungsziel||14)
}
if(desiredNum){
var dup=invoices.find(function(i){return i.status!=='draft'&&String(i.number||'').trim()===desiredNum&&i.id!==id});
if(dup){alert('Diese Rechnungsnummer existiert bereits!');return}
inv.number=desiredNum
}else{var fmtSel=document.querySelector('input[name="ieNumFormat"]:checked');inv.number=(fmtSel&&fmtSel.value==='re')?nextReInvNum():nextInvNum()}
inv.status='open';
inv.companySnapshot=JSON.parse(JSON.stringify(companyData));
recalcInvoice(inv);
addAuditEntry('Rechnung finalisiert','Rechnung',inv.number,'Kunde: '+inv.customerName+', Brutto: '+fmtCur(inv.grossTotal));
saveData();
hideInvoiceEditModal();
closeInvoiceDetailModal();
renderInvoices();
uiAlert('Rechnung '+inv.number+' finalisiert!','Rechnung')
}
async function deleteDraftInvoice(id){var inv=invoices.find(function(i){return i.id===id});if(!inv||inv.status!=='draft'){alert('Nur Entwürfe können gelöscht werden.');return}if(!await uiConfirm('Entwurf löschen?','Rechnung'))return;invoices=invoices.filter(function(i){return i.id!==id});saveData();closeInvoiceDetailModal();renderInvoices()}
