contentEl.innerHTML=(isStorno?'<div style="background:#fef2f2;border:2px solid #fca5a5;border-radius:12px;padding:14px 18px;margin-bottom:18px;text-align:center"><strong style="color:#dc2626">STORNIERT</strong>'+(inv.stornoDate?' am '+esc(inv.stornoDate):'')+' </div>':'')+'<div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:14px;margin-bottom:24px">'
