+'<div style="background:#f8fafc;border-radius:12px;padding:14px"><div style="font-size:10px;font-weight:700;letter-spacing:.07em;color:#94a3b8;margin-bottom:6px">DATUM</div><div style="font-size:12px;color:#374151"><div>Ausgestellt: <strong>'+esc(inv.issueDate||'-')+'</strong></div><div style="margin-top:4px">'+dueDateLabel+'</div></div></div>'
