async function exportInvoicePDF(id){if(hasCustomTemplate&&hasCustomTemplate('invoice')){var _inv=invoices.find(function(i){return i.id===id});if(!_inv){alert('Rechnung nicht gefunden.');return}if(_inv.status==='draft'){alert('Bitte zuerst finalisieren.');return}var _fn='Rechnung_'+(_inv.number||id)+'.pdf';var _ok=await autoSavePdfWithDocTemplate('invoice',_inv,_fn,'Rechnungen');if(!_ok)await exportPdfWithDocTemplate('invoice',_inv,_fn);return}var r=await buildInvoicePdfDoc(id);if(!r)return;return await savePdfDocument(r.doc,'Rechnung_'+r.inv.number+'.pdf',{autoSave:true,subDir:'Rechnungen'})}
async function masterDeleteInvoice(id){if(!isMaster())return;var inv=invoices.find(function(i){return i.id===id});if(!inv)return;if(!await uiConfirm('Rechnung '+(inv.number||'ENTWURF')+' endgültig löschen?','Master-Aktion'))return;invoices=invoices.filter(function(i){return i.id!==id});saveData();closeInvoiceDetailModal();renderInvoices()}
async function masterEditInvoiceNumber(id){if(!isMaster())return;var inv=invoices.find(function(i){return i.id===id});if(!inv)return;var oldNum=inv.number;var newNum=await uiPrompt('Neue Rechnungsnummer:',oldNum,'Rechnungsnummer ändern','z. B. RE-2026-1001');if(!newNum||!newNum.trim()||newNum.trim()===oldNum)return;var dup=invoices.find(function(i){return i.number===newNum.trim()&&i.id!==id});if(dup){alert('Diese Rechnungsnummer existiert bereits!');return}inv.number=newNum.trim();saveData();renderInvoices();if(selectedInvoiceId===id)renderInvoiceDetailModal(id)}
async function masterStornoInvoice(id){if(!isMaster())return;var inv=invoices.find(function(i){return i.id===id});if(!inv)return;if(inv.status==='storniert'){alert('Bereits storniert.');return}if(!await uiConfirm('Rechnung '+inv.number+' stornieren?','Master-Aktion'))return;inv.status='storniert';inv.stornoDate=new Date().toISOString().slice(0,10);saveData();renderInvoices();if(selectedInvoiceId===id)renderInvoiceDetailModal(id)}
function addDaysIso(iso,days){var d=iso?new Date(iso):new Date();if(!isFinite(d.getTime()))d=new Date();d.setDate(d.getDate()+(parseInt(days,10)||0));return d.toISOString().slice(0,10)}
function createRecurringDraftFromSchedule(sc){var today=new Date().toISOString().slice(0,10);var ym=today.slice(0,7);var exists=invoices.find(function(i){return i&&i.recurringScheduleId===sc.id&&String(i.recurringPeriod||'')===ym});if(exists)return null;var due=new Date(today+'T00:00:00');due.setDate(due.getDate()+(companyData.zahlungsziel||14));var copyLines=ensureArray(sc.lines).map(function(l){return Object.assign({},l,{id:'ln_'+Date.now()+'_'+Math.random().toString(16).slice(2)})});var inv={id:'inv_'+Date.now()+'_'+Math.random().toString(16).slice(2),number:'',orderId:'',customerId:sc.customerId||'',customerName:sc.customerName||'',customerAddress:sc.customerAddress||'',customerSalutation:sc.customerSalutation||'',customerFirstName:sc.customerFirstName||'',customerLastName:sc.customerLastName||'',customerCompany:sc.customerCompany||'',customerEmail:sc.customerEmail||'',object:sc.object||'',currency:sc.currency||'EUR',issueDate:today,dueDate:due.toISOString().slice(0,10),lines:copyLines,netTotal:0,vatRate:Number(sc.vatRate||0),vatTotal:0,grossTotal:0,status:'draft',kleinunternehmer:!!sc.kleinunternehmer,companySnapshot:JSON.parse(JSON.stringify(companyData)),createdAt:Date.now(),isRecurring:true,recurringScheduleId:sc.id,recurringPeriod:ym};recalcInvoice(inv);return inv}
function generateRecurringInvoicesIfDue(){if(recurringGenerationLock)return 0;recurringGenerationLock=true;try{recurringSchedules=ensureArray(recurringSchedules);if(!recurringSchedules.length)return 0;invoices=ensureArray(invoices);var today=new Date().toISOString().slice(0,10);var created=0;recurringSchedules.forEach(function(sc){if(!sc||sc.active===false)return;var guard=0;while(String(sc.nextIssueDate||'')&&sc.nextIssueDate<=today&&guard<24){var inv=createRecurringDraftFromSchedule(sc);if(inv){invoices.unshift(inv);created++;addAuditEntry('Wiederkehrende Rechnung erzeugt','Rechnung',inv.id,'Vorlage: '+(sc.sourceInvoiceNumber||sc.sourceInvoiceId||'-'))}sc.lastGeneratedAt=today;sc.nextIssueDate=addMonthsIso(sc.nextIssueDate,sc.intervalMonths||1);guard++}});if(created>0)saveData();return created}finally{recurringGenerationLock=false}}
async function createRecurringFromInvoice(id){invoices=ensureArray(invoices);var inv=invoices.find(function(i){return i&&i.id===id});if(!inv){alert('Rechnung nicht gefunden.');return}if(inv.status==='draft'||inv.status==='storniert'){alert('Nur offene/bezahlte Rechnungen können als Vorlage genutzt werden.');return}var intervalRaw=await uiPrompt('Intervall in Monaten (1 = monatlich, 3 = quartalsweise, 12 = jährlich):','1','Wiederkehrende Rechnung','1');if(intervalRaw===null)return;var interval=parseInt(String(intervalRaw||'').trim(),10);if([1,3,12].indexOf(interval)===-1){alert('Ungültiges Intervall. Erlaubt: 1, 3, 12.');return}var startDefault=addMonthsIso(new Date().toISOString().slice(0,10),interval);var firstDate=await uiPrompt('Erste automatische Erstellung (YYYY-MM-DD):',startDefault,'Startdatum',startDefault);if(firstDate===null)return;firstDate=String(firstDate||'').trim();if(!/^\d{4}-\d{2}-\d{2}$/.test(firstDate)){alert('Ungültiges Datum.');return}var existing=ensureArray(recurringSchedules).find(function(s){return s&&s.sourceInvoiceId===id&&s.active!==false});if(existing){existing.intervalMonths=interval;existing.nextIssueDate=firstDate;existing.active=true;addAuditEntry('Wiederkehrende Rechnung aktualisiert','Rechnung',id,'Intervall: '+interval+' Monate, nächster Lauf: '+firstDate)}else{var sc={id:'rec_'+Date.now()+'_'+Math.random().toString(16).slice(2),sourceInvoiceId:id,sourceInvoiceNumber:inv.number||'',customerId:inv.customerId||'',customerName:inv.customerName||'',customerAddress:inv.customerAddress||'',customerSalutation:inv.customerSalutation||'',customerFirstName:inv.customerFirstName||'',customerLastName:inv.customerLastName||'',customerCompany:inv.customerCompany||'',customerEmail:inv.customerEmail||'',object:inv.object||'',currency:inv.currency||'EUR',lines:JSON.parse(JSON.stringify(inv.lines||[])),vatRate:Number(inv.vatRate||0),kleinunternehmer:!!inv.kleinunternehmer,intervalMonths:interval,nextIssueDate:firstDate,lastGeneratedAt:'',active:true,createdAt:Date.now()};recurringSchedules.unshift(sc);addAuditEntry('Wiederkehrende Rechnung angelegt','Rechnung',id,'Intervall: '+interval+' Monate, erster Lauf: '+firstDate)}await saveData();renderInvoices();alert('Wiederkehrende Rechnung gespeichert.')}
function xmlEsc(s){s=String(s==null?'':s);return s.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;')}
function amt(n){return (Number(n)||0).toFixed(2)}
function unitCode(u){u=String(u||'').toLowerCase().trim();if(!u||u==='pauschal'||u==='psch'||u==='pau')return'LS';if(u==='stk'||u==='st'||u==='stck'||u==='stueck'||u==='stück'||u==='piece'||u==='pcs')return'H87';if(u==='std'||u==='stunde'||u==='stunden'||u==='h'||u==='hr'||u==='hour')return'HUR';if(u==='min'||u==='minute'||u==='minuten')return'MIN';if(u==='tag'||u==='tage'||u==='d'||u==='day')return'DAY';if(u==='m'||u==='lfm'||u==='meter')return'MTR';if(u==='m2'||u==='m²'||u==='qm'||u==='quadratmeter')return'MTK';if(u==='m3'||u==='m³'||u==='cbm'||u==='kubikmeter')return'MTQ';if(u==='cm')return'CMT';if(u==='mm')return'MMT';if(u==='km')return'KTM';if(u==='kg'||u==='kilo'||u==='kilogramm')return'KGM';if(u==='g'||u==='gramm')return'GRM';if(u==='t'||u==='tonne'||u==='tonnen')return'TNE';if(u==='l'||u==='liter')return'LTR';if(u==='ml'||u==='milliliter')return'MLT';if(u==='pa'||u==='paar')return'PR';if(u==='satz'||u==='set')return'SET';if(u==='kt'||u==='karton'||u==='ktn')return'CT';if(u==='pa.'||u==='pak'||u==='paket'||u==='pack'||u==='pkt')return'PK';return'C62'}
function buildXRechnungXML(inv){var cs=inv.companySnapshot||companyData;var vatPct=Math.round((inv.vatRate||0)*100);var buyerAddr=(inv.customerAddress||'').split(',');var linesXml=(inv.lines||[]).map(function(l){return'<cac:InvoiceLine>'+'<cbc:ID>'+xmlEsc(l.pos)+'</cbc:ID>'+'<cbc:InvoicedQuantity unitCode="'+unitCode(l.unit)+'">'+amt(l.qty)+'</cbc:InvoicedQuantity>'+'<cbc:LineExtensionAmount currencyID="'+xmlEsc(inv.currency||'EUR')+'">'+amt(l.lineTotal)+'</cbc:LineExtensionAmount>'+'<cac:Item>'+'<cbc:Name>'+xmlEsc(l.title||'')+'</cbc:Name>'+(l.description?'<cbc:Description>'+xmlEsc(l.description)+'</cbc:Description>':'')+'<cac:ClassifiedTaxCategory>'+'<cbc:ID>'+(inv.kleinunternehmer?'O':'S')+'</cbc:ID>'+'<cbc:Percent>'+amt(vatPct)+'</cbc:Percent>'+'<cac:TaxScheme><cbc:ID>VAT</cbc:ID></cac:TaxScheme>'+'</cac:ClassifiedTaxCategory>'+'</cac:Item>'+'<cac:Price><cbc:PriceAmount currencyID="'+xmlEsc(inv.currency||'EUR')+'">'+amt(l.unitPrice)+'</cbc:PriceAmount></cac:Price>'+'</cac:InvoiceLine>'}).join('');var taxXml=inv.kleinunternehmer?'<cac:TaxTotal><cbc:TaxAmount currencyID="'+xmlEsc(inv.currency||'EUR')+'">0.00</cbc:TaxAmount></cac:TaxTotal>':'<cac:TaxTotal><cbc:TaxAmount currencyID="'+xmlEsc(inv.currency||'EUR')+'">'+amt(inv.vatTotal)+'</cbc:TaxAmount><cac:TaxSubtotal><cbc:TaxableAmount currencyID="'+xmlEsc(inv.currency||'EUR')+'">'+amt(inv.netTotal)+'</cbc:TaxableAmount><cbc:TaxAmount currencyID="'+xmlEsc(inv.currency||'EUR')+'">'+amt(inv.vatTotal)+'</cbc:TaxAmount><cac:TaxCategory><cbc:ID>S</cbc:ID><cbc:Percent>'+amt(vatPct)+'</cbc:Percent><cac:TaxScheme><cbc:ID>VAT</cbc:ID></cac:TaxScheme></cac:TaxCategory></cac:TaxSubtotal></cac:TaxTotal>';var payXml='<cac:PaymentMeans><cbc:PaymentMeansCode>31</cbc:PaymentMeansCode><cac:PayeeFinancialAccount>'+(cs.iban?'<cbc:ID>'+xmlEsc(cs.iban)+'</cbc:ID>':'')+'</cac:PayeeFinancialAccount>'+(cs.bic?'<cac:FinancialInstitutionBranch><cbc:ID>'+xmlEsc(cs.bic)+'</cbc:ID></cac:FinancialInstitutionBranch>':'')+'</cac:PaymentMeans>';var xml='<?xml version="1.0" encoding="UTF-8"?>'+'<Invoice xmlns="urn:oasis:names:specification:ubl:schema:xsd:Invoice-2" xmlns:cac="urn:oasis:names:specification:ubl:schema:xsd:CommonAggregateComponents-2" xmlns:cbc="urn:oasis:names:specification:ubl:schema:xsd:CommonBasicComponents-2">'+'<cbc:CustomizationID>urn:cen.eu:en16931:2017</cbc:CustomizationID>'+'<cbc:ProfileID>urn:fdc:peppol.eu:2017:poacc:billing:01:1.0</cbc:ProfileID>'+'<cbc:ID>'+xmlEsc(inv.number||'')+'</cbc:ID>'+'<cbc:IssueDate>'+xmlEsc(inv.issueDate||'')+'</cbc:IssueDate>'+(inv.dueDate?'<cbc:DueDate>'+xmlEsc(inv.dueDate)+'</cbc:DueDate>':'')+'<cbc:InvoiceTypeCode>380</cbc:InvoiceTypeCode>'+'<cbc:DocumentCurrencyCode>'+xmlEsc(inv.currency||'EUR')+'</cbc:DocumentCurrencyCode>'+'<cac:AccountingSupplierParty><cac:Party><cbc:Name>'+xmlEsc((cs.firma||''))+'</cbc:Name><cac:PostalAddress>'+(cs.strasse?'<cbc:StreetName>'+xmlEsc(cs.strasse)+'</cbc:StreetName>':'')+(cs.plz?'<cbc:PostalZone>'+xmlEsc(cs.plz)+'</cbc:PostalZone>':'')+(cs.ort?'<cbc:CityName>'+xmlEsc(cs.ort)+'</cbc:CityName>':'')+'<cac:Country><cbc:IdentificationCode>DE</cbc:IdentificationCode></cac:Country></cac:PostalAddress>'+(cs.ustId?'<cac:PartyTaxScheme><cbc:CompanyID>'+xmlEsc(cs.ustId)+'</cbc:CompanyID><cac:TaxScheme><cbc:ID>VAT</cbc:ID></cac:TaxScheme></cac:PartyTaxScheme>':'')+'</cac:Party></cac:AccountingSupplierParty>'+'<cac:AccountingCustomerParty><cac:Party><cbc:Name>'+xmlEsc(inv.customerCompany||inv.customerName||'')+'</cbc:Name><cac:PostalAddress>'+(buyerAddr[0]?'<cbc:StreetName>'+xmlEsc((buyerAddr[0]||'').trim())+'</cbc:StreetName>':'')+(buyerAddr[1]?'<cbc:CityName>'+xmlEsc((buyerAddr[1]||'').trim())+'</cbc:CityName>':'')+'<cac:Country><cbc:IdentificationCode>DE</cbc:IdentificationCode></cac:Country></cac:PostalAddress></cac:Party></cac:AccountingCustomerParty>'+payXml+taxXml+'<cac:LegalMonetaryTotal><cbc:LineExtensionAmount currencyID="'+xmlEsc(inv.currency||'EUR')+'">'+amt(inv.netTotal)+'</cbc:LineExtensionAmount><cbc:TaxExclusiveAmount currencyID="'+xmlEsc(inv.currency||'EUR')+'">'+amt(inv.netTotal)+'</cbc:TaxExclusiveAmount><cbc:TaxInclusiveAmount currencyID="'+xmlEsc(inv.currency||'EUR')+'">'+amt(inv.grossTotal)+'</cbc:TaxInclusiveAmount><cbc:PayableAmount currencyID="'+xmlEsc(inv.currency||'EUR')+'">'+amt(inv.grossTotal)+'</cbc:PayableAmount></cac:LegalMonetaryTotal>'+linesXml+'</Invoice>';return xml}
function exportInvoiceXRechnungXML(id){var inv=invoices.find(function(i){return i.id===id});if(!inv){alert('Rechnung nicht gefunden.');return}if(inv.status==='draft'){alert('Bitte zuerst finalisieren.');return}var xml=buildXRechnungXML(inv);var blob=new Blob([xml],{type:'application/xml'});var a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download='XRechnung-'+(inv.number||'')+'.xml';document.body.appendChild(a);a.click();setTimeout(function(){URL.revokeObjectURL(a.href);document.body.removeChild(a)},500)}

function openAddPaymentDialog(invId){
  var inv=invoices.find(function(i){return i.id===invId});
  if(!inv)return;
  var paid=getInvPaidTotal(inv);
  var gross=Number(inv.grossTotal)||0;
  var remaining=Math.max(0,gross-paid);
  var today=new Date().toISOString().slice(0,10);
  var el=document.createElement('div');
  el.id='paymentDialog';
  el.style.cssText='position:fixed;inset:0;background:rgba(0,0,0,.5);z-index:9999;display:flex;align-items:center;justify-content:center';
  el.innerHTML='<div style="background:#fff;border-radius:16px;padding:28px;min-width:340px;max-width:420px;width:90%;box-shadow:0 20px 60px rgba(0,0,0,.3)">'
    +'<div style="font-size:16px;font-weight:800;color:#0f172a;margin-bottom:4px">Zahlung erfassen</div>'
    +'<div style="font-size:12px;color:#6b7280;margin-bottom:18px">Rechnung '+esc(inv.number||'-')+' · Gesamt: '+fn(gross)+' €'+(paid>0?' · Bereits bezahlt: '+fn(paid)+' €':'')+'</div>'
    +'<div style="margin-bottom:12px"><label style="font-size:12px;font-weight:700;color:#64748b;display:block;margin-bottom:4px">Datum</label>'
    +'<input id="payDlgDate" type="date" value="'+today+'" style="width:100%;padding:8px 12px;border:1.5px solid #e2e8f0;border-radius:8px;font-size:14px;box-sizing:border-box"></div>'
    +'<div style="margin-bottom:12px"><label style="font-size:12px;font-weight:700;color:#64748b;display:block;margin-bottom:4px">Betrag (€)'+(remaining>0?' — Noch offen: '+fn(remaining)+' €':'')+'</label>'
    +'<input id="payDlgAmount" type="number" min="0.01" step="0.01" value="'+(remaining>0?remaining.toFixed(2):'')+'" placeholder="0,00" style="width:100%;padding:8px 12px;border:1.5px solid #e2e8f0;border-radius:8px;font-size:14px;box-sizing:border-box"></div>'
    +'<div style="margin-bottom:20px"><label style="font-size:12px;font-weight:700;color:#64748b;display:block;margin-bottom:4px">Notiz (optional)</label>'
    +'<input id="payDlgNote" type="text" placeholder="z.B. Überweisung, Bar, EC-Karte" style="width:100%;padding:8px 12px;border:1.5px solid #e2e8f0;border-radius:8px;font-size:14px;box-sizing:border-box"></div>'
    +'<div style="display:flex;gap:10px;justify-content:flex-end">'
    +'<button onclick="document.getElementById(\'paymentDialog\').remove()" style="padding:8px 18px;border:1.5px solid #e2e8f0;border-radius:8px;background:#fff;font-size:13px;font-weight:600;cursor:pointer;color:#374151">Abbrechen</button>'
    +'<button onclick="savePaymentEntry(\''+invId+'\')" style="padding:8px 18px;border:none;border-radius:8px;background:#16a34a;color:#fff;font-size:13px;font-weight:700;cursor:pointer">Speichern</button>'
    +'</div></div>';
  document.body.appendChild(el);
  el.addEventListener('click',function(e){if(e.target===el)el.remove()});
  setTimeout(function(){var a=document.getElementById('payDlgAmount');if(a)a.focus()},50);
}

function savePaymentEntry(invId){
  var inv=invoices.find(function(i){return i.id===invId});
  if(!inv)return;
  var date=document.getElementById('payDlgDate').value;
  var amount=parseFloat(String(document.getElementById('payDlgAmount').value).replace(',','.'));
  var note=(document.getElementById('payDlgNote').value||'').trim();
  if(!date||isNaN(amount)||amount<=0){alert('Bitte Datum und gültigen Betrag eingeben.');return}
  if(!inv.payments)inv.payments=[];
  inv.payments.push({id:'pay_'+Date.now(),date:date,amount:Math.round(amount*100)/100,note:note});
  recalcInvStatus(inv);
  addAuditEntry('Zahlung erfasst','Rechnung',inv.number,fn(amount)+' € am '+date+(note?' ('+note+')':''));
  saveData();
  var dlg=document.getElementById('paymentDialog');if(dlg)dlg.remove();
  renderInvoices();
  if(selectedInvoiceId===invId)renderInvoiceDetailModal(invId);
}

async function deletePaymentEntry(invId,payId){
  if(!await uiConfirm('Zahlung wirklich löschen?','Löschen'))return;
  var inv=invoices.find(function(i){return i.id===invId});
  if(!inv)return;
  inv.payments=(inv.payments||[]).filter(function(p){return p.id!==payId});
  recalcInvStatus(inv);
  addAuditEntry('Zahlung gelöscht','Rechnung',inv.number,'');
  saveData();renderInvoices();
  if(selectedInvoiceId===invId)renderInvoiceDetailModal(invId);
}

async function deleteInvoice(id){
  var inv=invoices.find(function(i){return i.id===id});
  if(!inv)return;
  if(!await uiConfirm('Rechnung '+(inv.number||'-')+' endgültig löschen?','Löschen'))return;
  invoices=invoices.filter(function(i){return i.id!==id});
  saveData();
  closeInvoiceDetailModal();
  renderInvoices();
}
var _ieLineDragSrcIdx=null;
function ieLineDragStart(e,idx,invId){_ieLineDragSrcIdx=idx;e.currentTarget.style.opacity='0.5';e.currentTarget.style.background='#f0f9ff';e.dataTransfer.effectAllowed='move'}
function ieLineDragOver(e){e.preventDefault();e.currentTarget.style.borderColor='#0891b2';e.dataTransfer.dropEffect='move';return false}
function ieLineDrop(e,invId,toIdx){e.stopPropagation();e.currentTarget.style.borderColor='';if(_ieLineDragSrcIdx!==null&&_ieLineDragSrcIdx!==toIdx)moveInvoiceLine(invId,_ieLineDragSrcIdx,toIdx);_ieLineDragSrcIdx=null;return false}
function ieLineDragEnd(){_ieLineDragSrcIdx=null;document.querySelectorAll('.ie-drag-item').forEach(function(el){el.style.opacity='1';el.style.background='';el.style.borderColor=''})}
function moveInvoiceLine(invId,fromIdx,toIdx){var inv=invoices.find(function(i){return i.id===invId});if(!inv||fromIdx===toIdx)return;var moved=inv.lines.splice(fromIdx,1)[0];inv.lines.splice(toIdx,0,moved);inv.lines.forEach(function(l,i){l.pos=i+1});recalcInvoice(inv);renderInvoiceEditLines(inv);saveDataSoon()}
